    ('Heinz', 'Tomato Ketchup 50% weniger Zucker & Salz', 'https://images.openfoodfacts.org/images/products/871/570/042/3869/front_fr.130.400.jpg', 'off_api', 'front', true, 'Front — EAN 8715700423869', 'front_8715700423869'),
    ('Rewe Bio', 'Ketchup', 'https://images.openfoodfacts.org/images/products/438/884/400/7901/front_de.47.400.jpg', 'off_api', 'front', true, 'Front — EAN 4388844007901', 'front_4388844007901'),
    ('Alnatura', 'Tomaten Ketchup', 'https://images.openfoodfacts.org/images/products/410/442/003/1500/front_en.102.400.jpg', 'off_api', 'front', true, 'Front — EAN 4104420031500', 'front_4104420031500')
) AS d(brand, product_name, url, source, image_type, is_primary, alt_text, off_image_id)
JOIN products p ON p.country = 'DE' AND p.brand = d.brand AND p.product_name = d.product_name
  AND p.category = 'Condiments' AND p.is_deprecated IS NOT TRUE
ON CONFLICT (off_image_id) WHERE off_image_id IS NOT NULL DO UPDATE SET
  url = EXCLUDED.url,
  image_type = EXCLUDED.image_type,
  is_primary = EXCLUDED.is_primary,
  alt_text = EXCLUDED.alt_text;
